function shortDate(date: string | null): string {
  if (!date) return "—";
  return new Date(date).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
  });
}

function statusLabel(status: string): string {
  return STATUS_CONFIG[status as IssueStatus]?.label ?? status;
}

function priorityLabel(priority: string): string {
  return PRIORITY_CONFIG[priority as IssuePriority]?.label ?? priority;
}

function repoLabel(repoUrl?: string | null): string {
  if (!repoUrl) return "No repository";
  const trimmed = repoUrl.replace(/\/+$/, "");
  const parts = trimmed.split("/");
  return parts.length >= 2 ? `${parts[parts.length - 2]}/${parts[parts.length - 1]}` : repoUrl;
}

function executionStageLabel(stage: IssueExecutionStage): string {
  switch (stage) {
    case "planning":
      return "Planning";
    case "plan_ready":
      return "Plan Ready";
    case "build_ready":
      return "Build Ready";
    case "building":
      return "Building";
    default:
      return "Idle";
  }
}

function getTaskResult(task: AgentTask | null): AgentTaskResult | null {
  if (!task?.result || typeof task.result !== "object") {
    return null;
  }
  return task.result as AgentTaskResult;
}

function formatActivity(
  entry: TimelineEntry,
  resolveActorName?: (type: string, id: string) => string,
): string {
  const details = (entry.details ?? {}) as Record<string, unknown>;
  const detailString = (value: unknown, fallback = "?") =>
    typeof value === "string" && value ? value : fallback;
  switch (entry.action) {
    case "created":
      return "created this issue";
    case "status_changed":
      return `changed status from ${statusLabel(detailString(details.from))} to ${statusLabel(detailString(details.to))}`;
    case "priority_changed":
      return `changed priority from ${priorityLabel(detailString(details.from))} to ${priorityLabel(detailString(details.to))}`;
    case "…167 chars truncated… this issue";
      const toType = typeof details.to_type === "string" ? details.to_type : null;
      const toID = typeof details.to_id === "string" ? details.to_id : null;
      const fromID = typeof details.from_id === "string" ? details.from_id : null;
      const toName = toID && toType && resolveActorName
        ? resolveActorName(toType, toID)
        : null;
      if (toName) return `assigned to ${toName}`;
      if (fromID && !toID) return "removed assignee";
      return "changed assignee";
    }
    case "due_date_changed": {
      const toValue = typeof details.to === "string" ? details.to : "";
      if (!toValue) return "removed due date";
      const formatted = new Date(toValue).toLocaleDateString("en-US", { month: "short", day: "numeric" });
      return `set due date to ${formatted}`;
    }
    case "title_changed":
      return `renamed this issue from "${detailString(details.from)}" to "${detailString(details.to)}"`;
    case "description_updated":
      return "updated the description";
    case "task_completed":
      if (details.delivery_state === "delivered") return "prepared delivery for review";
      if (details.delivery_state === "handoff_required") return "prepared review handoff";
      if (details.delivery_state === "completed" && (details.compare_url || details.branch_name)) {
        return "prepared delivery and is waiting for PR automation";
      }
      return "completed the run";
    case "delivery_ready":
      return "prepared delivery for review";
    case "delivery_handoff_required":
      return "prepared review handoff";
    case "task_failed":
      return "run failed";
    default:
      return entry.action ?? "";
  }
}


